class ValidatedState(TypedDict):
    agent_outputs: dict[str, Any]
    shared_data: dict[str, Any]

class StateSchema(BaseModel):
    agent_outputs: dict[str, Any]
    shared_data: dict[str, Any]

    @validator('agent_outputs')
    def check_conflicts(cls, v):
        if len(v) > 1:
            keys = set()
            for outputs in v.values():
                if isinstance(outputs, dict):
                    key_conflicts = keys.intersection(outputs.keys())
                    if key_conflicts:
                        raise ValueError(f"State conflict: {key_conflicts}")
                    keys.update(outputs.keys())
        return v

# Add as validation node
def validate_state(state: ValidatedState) -> ValidatedState:
    schema = StateSchema(**state)
    return state

