from typing import TypedDict, Annotated
import operator
from datetime import datetime

class VersionedState(TypedDict):
    data: dict[str, Any]
    version: Annotated[int, operator.add]
    last_updated: dict[str, datetime]

# Atomic update pattern
def atomic_update(state: VersionedState, agent_id: str, updates: dict) -> VersionedState:
    current_version = state['version']

    # Check for concurrent modification
    if 'expected_version' in updates and updates['expected_version'] != current_version:
        raise ValueError(f"Concurrent modification detected for {agent_id}")

    # Apply atomic update
    new_data = state['data'].copy()
    new_data.update(updates.get('data', {}))

    return {
        **state,
        'data': new_data,
        'version': current_version + 1,
        'last_updated': {**state.get('last_updated', {}), agent_id: datetime.now()}
    }

# Agent node wrapper
def safe_agent_node(state: VersionedState, agent_id: str):
    try:
        updates = agent_function(state)
        updates['expected_version'] = state['version']
        return atomic_update(state, agent_id, updates)
    except ValueError:
        return {"messages": [f"Conflict detected from {agent_id}, retrying..."]}

