from langgraph.graph import StateGraph
from typing import Literal

class State(TypedDict):
    messages: list
    requires_human: bool
    interrupt_priority: Literal["HIGH", "MEDIUM", "LOW"]

# Priority-based routing
def human_review_router(state: State):
    if state.get('requires_human'):
        return "INTERRUPT"
    if state.get('interrupt_priority') == "HIGH":
        return "INTERRUPT"
    return "continue"

# Graph with guaranteed HITL
graph = StateGraph(State)
graph.add_conditional_edges(
    "agent",
    human_review_router,
    {
        "INTERRUPT": "human_review",
        "continue": "next_agent"
    }
)

# Human review node always interrupts
graph.add_node("human_review", lambda state: {
    **state,
    "messages": state["messages"] + ["WAITING FOR HUMAN INPUT"]
})

